MERGE  STOCVNFI  VNFI
USING (
    SELECT #{ses.gateCd} AS GATE_CD
        , #{VENDOR_CD} AS VENDOR_CD
        , #{FI_YEAR} AS FI_YEAR

    ) PARAM
    ON (PARAM.GATE_CD = VNFI.GATE_CD
    AND PARAM.VENDOR_CD = VNFI.VENDOR_CD
    AND PARAM.FI_YEAR = VNFI.FI_YEAR)
WHEN MATCHED THEN
UPDATE SET
    MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , DEL_FLAG = '0'
    , EVIDENCE_TYPE = #{EVIDENCE_TYPE}
    , OWNER_CAPITAL_AMOUNT = #{OWNER_CAPITAL_AMOUNT}
    , TOT_FUND_AMT = #{TOT_FUND_AMT}
    , TOT_LIAB_AMT = #{TOT_LIAB_AMT}
    , TOTAL_LIABILITY_RATE = #{TOTAL_LIABILITY_RATE}
    , CURRENT_ASSET_AMOUNT = #{CURRENT_ASSET_AMOUNT}
    , CURRENT_ASSET_LIABILITY_AMOUNT = #{CURRENT_ASSET_LIABILITY_AMOUNT}
    , SALES_AMOUNT = #{SALES_AMOUNT}
    , NET_PROFIT_AMOUNT = #{NET_PROFIT_AMOUNT}
    , ATT_FILE_NUM = #{VNFI_ATT_FILE_NUM}
WHEN NOT MATCHED THEN
INSERT (
    GATE_CD
    , VENDOR_CD
    , FI_YEAR
    , EVIDENCE_TYPE
    , OWNER_CAPITAL_AMOUNT
    , TOT_FUND_AMT
    , TOT_LIAB_AMT
    , TOTAL_LIABILITY_RATE
    , CURRENT_ASSET_AMOUNT
    , CURRENT_ASSET_LIABILITY_AMOUNT
    , SALES_AMOUNT
    , NET_PROFIT_AMOUNT
    , ATT_FILE_NUM
    , REG_DATE
    , REG_USER_ID
    , MOD_DATE
    , MOD_USER_ID
    , DEL_FLAG
) VALUES (
    #{ses.gateCd}
    , #{VENDOR_CD}
    , #{FI_YEAR}
    , #{EVIDENCE_TYPE}
    , #{OWNER_CAPITAL_AMOUNT}
    , #{TOT_FUND_AMT}
    , #{TOT_LIAB_AMT}
    , #{TOTAL_LIABILITY_RATE}
    , #{CURRENT_ASSET_AMOUNT}
    , #{CURRENT_ASSET_LIABILITY_AMOUNT}
    , #{SALES_AMOUNT}
    , #{NET_PROFIT_AMOUNT}
    , #{VNFI_ATT_FILE_NUM}
    , SYSDATE
    , #{ses.userId}
    , SYSDATE
    , #{ses.userId}
    , '0'
)

        UPDATE TB_CO_CORP SET
			REP_NM = DAMO.ENCRYPT_VAR_B64('EBILL_AES_256',  #{CEO_USER_NM},  '' )  
			, BIZTP = #{BUSINESS_TYPE}
			, BZC = #{INDUSTRY_TYPE}     
			, ZIP = DAMO.ENCRYPT_VAR_B64('EBILL_AES_256',  #{HQ_ZIP_CD},  '' )  
        	, ADDR = DAMO.ENCRYPT_VAR_B64('EBILL_AES_256',  #{HQ_ADDR_1},  '' )
        	, DTL_ADDR = DAMO.ENCRYPT_VAR_B64('EBILL_AES_256',  #{HQ_ADDR_2},  '' )
			, REP_TEL = DAMO.ENCRYPT_VAR_B64('EBILL_AES_256',  #{TEL_NO},  '' )
			, FAX = DAMO.ENCRYPT_VAR_B64('EBILL_AES_256',  #{FAX_NO},  '' ) 
			, CORP_ROW_NO = #{COMPANY_REG_NO}
            , LSCHGDTM = SYSDATE
            , LSCHGID = #{ses.userId}
        WHERE CORP_NO = #{IRS_NO}

