INSERT INTO STOCVNSL (
    GATE_CD
    , COMPANY_CD
    , COMPANY_DEPT_CD
    , SEQ
    , REG_DATE
    , REG_USER_ID
    , MOD_DATE
    , MOD_USER_ID
    , DEL_FLAG
    , SL_TYPE
    , SL_NUM
    , SL_NM
    , ISSUE_NM
    , EXPIRY_DATE
    , ATT_FILE_NUM
) VALUES (
    #{ses.gateCd}
    , #{COMPANY_CD}
    , '0000' -- 협력사는 0000, 고객사는 해당부서
    , (SELECT (MAX(TO_NUMBER(SEQ)), 0) + 1 FROM STOCVNSL WHERE GATE_CD = #{GATE_CD} AND COMPANY_CD = #{COMPANY_CD})
    , SYSDATE
    , #{ses.userId}
    , SYSDATE
    , #{ses.userId}
    , '0'
    , #{SL_TYPE}
    , #{SL_NUM}
    , #{SL_NM}
    , #{ISSUE_NM}
    , #{EXPIRY_DATE}
    , #{ATT_FILE_NUM}
)

